var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"끄응. 불편한 자세로 있었더니 멀미라도 하는 기분이군.","JPN":"ぐぬぬ。慣れない姿勢を続けていたせいか乗り物酔いでもした気分じゃ。","ENG":"Ugh. Sitting in that awkward position has me feeling queasy.","TWN":"呃嗯，因為姿勢很不舒服，感覺有點暈車。"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L4_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"요 커다란 건물이 녀석들이 말한 연구소냐?","JPN":"この大きな建物が、さっき話していた研究所とやらか？","ENG":"That big building there, is that the lab they were talking about?","TWN":"這棟巨大的建築物就是妳們說的研究所嗎？"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"응. 한 번 무너졌었는데, 쓸만한 게 많아서 내 능력으로 재건시켰어.","JPN":"うん。一度崩壊したけど、使えるものが多かったから私の能力で再建した。","ENG":"Yeah. It collapsed once, but there was a lot worth salvaging, so I rebuilt it with my ability.","TWN":"嗯，之前倒塌過一次，但因為能用的東西很多，就用我的能力重建了。"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"위험한 설비가 많아서 다들 필요할 때를 제외하고는 오지 않지만…….","JPN":"危険な設備が多いから、特に用事がない限り誰も来ないけど……","ENG":"There are lots of hazardous systems, so no one comes here unless they need to, but...","TWN":"因為有很多危險設備，除了有需要的時候大家都不會來……"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"딱 한 명. 주기적으로 이 시설을 방문하는 사람이 있어.","JPN":"1人だけ、定期的にこの施設を訪ねる人がいる。","ENG":"There is exactly one person who visits this facility regularly.","TWN":"但是只有一個人會定期跑來這座設施。"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"이번 일도 아마 그 사람의 소행이겠지.","JPN":"今回の件も、たぶんあの人の仕業だと思う。","ENG":"This business is probably her doing too.","TWN":"這次的事應該是那個人所為。"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"어느 마을이나 장난꾸러기 한 명은 있는 법이지~.","JPN":"どの村にもいたずらっ子はいるものじゃ。","ENG":"Every town has at least one troublemaker.","TWN":"每個村子都會有一個搗蛋鬼～"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"너나 민병단이나, 그 녀석 관리하느라 애 좀 먹겠구나.","JPN":"お主も民兵団も、そいつの扱いには苦労しておるようじゃな。","ENG":"You and the militia must have your hands full keeping her in line.","TWN":"妳和民兵團為了管理那個傢伙應該吃了不少苦。"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"굳이 따지면 마을 사람은 아니야. 잠시 거처를 빌려주고 있을 뿐이거든.","JPN":"厳密に言うと村の人じゃないよ。しばらく生活できるように場所を貸してるだけ。","ENG":"Strictly speaking, she isn't a villager. We are just letting her stay for a while.","TWN":"如果非要追究的話，她不是村子裡的人，只是暫時借她地方住而已。"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"그 녀석, 이름은?","JPN":"そいつの名は？","ENG":"What is her name?","TWN":"那個傢伙的名字是？"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"레노어.","JPN":"レノア。","ENG":"Lenore.","TWN":"蕾諾雅。"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"제길. 나쁜 예감은 항상 틀려가질 않는군.","JPN":"やっぱりか。悪い予感は外れることがないのう。","ENG":"Figures. My bad hunches never seem to be wrong.","TWN":"該死，不祥的預感總是不會出錯。"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"……사람의 흔적.","JPN":"……人の気配。","ENG":"...Human tracks.","TWN":"……有人的痕跡。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L23_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"한 명이 아니야. 아무래도 일행이 있는 것 같아.","JPN":"1人じゃない。どうやら連れがいるみたいだね。","ENG":"It's not just one. Looks like they have company.","TWN":"不只一個人，總覺得應該是一行人。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_COMBAT_ALL_TECH_02"},{"id":"L26_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"그래. 세 명… 거기에 인간이 아닌 것의 흔적도 보이는구나.","JPN":"ああ、3人……それに、人間ではないものの痕跡もあるのう。","ENG":"Right. Three... And I can see traces of something non-human as well.","TWN":"沒錯，三個人…那裡也有不是人類的痕跡。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"여러 명이서 금지 구역을 넘어갔다면 좋은 꿍꿍이는 아닌 듯싶은데, 어떡할 거냐?","JPN":"連れ立って立入禁止エリアに入ったということは、何か良からぬことを企んでおるようじゃが……どうする？","ENG":"If several of them crossed into the off-limits zone, that cannot be for anything good. What do you want to do?","TWN":"如果是好幾個人越過禁區的話，應該是不懷好意，該怎麼辦？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L28_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"다른 민병단원들을 기다리기만 해선 늦을지도 몰라.","JPN":"他の民兵団員を待っていたら、間に合わないかもしれない。","ENG":"If we just wait for the other militia members, we might be too late.","TWN":"一直乾等其他民兵團員可能會來不及。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L29_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"조용하게 움직인다면 그만큼 들키기 싫다는 거니까…….","JPN":"静かに動いてるってことは、バレたくないということだから……","ENG":"If they are moving quietly, that means they don't want to be noticed...","TWN":"如果是安靜地行動，就代表是不想被發現……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L30_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"시간을 주지 않는 편이 유리할 거라 생각해.","JPN":"時間を与えないほうが、有利になると思う。","ENG":"We're better off not giving them time.","TWN":"我覺得不要給她們時間會比較有利。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L31_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"동감이다. 어린 것이 야무지기까지 하니 보면 볼수록 탐나는군.","JPN":"わしも同意見じゃ。若いのに頭の回転も速いとは、見れば見るほど欲しくなるのう。","ENG":"Agreed. You are young and sharp. The more I see, the more I want to recruit you.","TWN":"我贊同，看妳小小年紀還這麼幹練，越看越感興趣。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"좋아, 미래의 제자님이 싸운다는데 지켜보고 있을 수만은 없지.","JPN":"よし。未来の弟子が戦いに臨むというのに、ただ見ているわけにはいかん。","ENG":"All right, if my future apprentice is fighting, I cannot just stand by and watch.","TWN":"很好，未來的徒弟都說要戰鬥了，總不能只是袖手旁觀。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L34_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"레노어 녀석에게 빚진 것도 있으니, 내 특별히 손을 빌려주마.","JPN":"レノアのやつには借りがあるし、特別に手伝ってやろう。","ENG":"I owe Lenore too, so I will lend you my strength.","TWN":"我對蕾諾雅那傢伙也有所虧欠，就特別助你一臂之力吧。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"침식된 이터니움이 마흔 일곱… 마흔 여덟…….","JPN":"侵食されたエタニウムが47……48……","ENG":"Forty-seven... Forty-eight Corrupted Eterniums...","TWN":"被侵蝕的永恆之金有47…48……"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL"},{"id":"L40_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"맥없는 소리로 말하지 마. 고작 이터니움 챙기는 게 뭐가 힘들다고 그렇게 투덜거려?","JPN":"力抜けた声で数えないでくれる？　たかがエタニウムを運ぶくらい、ぶつぶつ言うほど大変じゃないでしょ。","ENG":"Quit whining. You're just packing Eternium. What's so hard that you have to gripe like that?","TWN":"不要用無精打采的聲音說話，不過是拿個永恆之金有這麼累嗎？還那樣嘀嘀咕咕的？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"HATE2"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"그래. 고작 이터니움 챙기자고 지금껏 이 고생을 했지.","JPN":"まあ、その「たかがエタニウム」のわりには、随分険しい道のりではあったけど。","ENG":"Right, we went through hell all this time just to pack Eternium.","TWN":"是啊，一直以來吃了這麼多苦就只是為了要拿永恆之金。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"그런데 여기 있는 건 너무 적지 않아?","JPN":"でもここにあるのは少なすぎるんじゃない？","ENG":"But is this not way too little for what's here?","TWN":"但這裡的會不會太少？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L46_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"시, 실험은 다른 연구소에서도 진행되었으니 선로전환기를 위한 분량은 이미 확보되었을 거예요.","JPN":"じ、実験は他の研究所でも行われていたので、線路転換器のための分はすでに確保済みだと思います。","ENG":"Th-the experiments were conducted at other labs too, so the amount for the Track Switcher should already be secured.","TWN":"其、其他研究所也有進行實驗，應該已經確保線路轉換器需要的分量了。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L47_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"많으면 많을수록 좋으니까, 여, 여기 온 거고요.","JPN":"でも多ければ多いほどいいから、こ、ここに来たんです。","ENG":"More is always better. That's why we came here.","TWN":"因為越多越好，所、所以才會來這裡。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L48_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"에휴, 결국 펠릭스의 뒤치다꺼리나 하는 셈이네.","JPN":"はあ、結局はフェリックスにこき使われてるのよね。","ENG":"Figures. We're basically cleaning up Felix's mess again.","TWN":"唉唷，到頭來等於是在替緋莉克絲善後。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L49_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"그런데, 시민들 눈을 피해서 이걸 전부 옮길 방법은 있어?","JPN":"でも、人にバレずにこれを全部持ち出す方法なんてあるの？","ENG":"Anyway, do we have a way to move all of this without the townsfolk seeing?","TWN":"但是有能避開市民視線，把這些全部移走的方法嗎？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L1_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"걱정 마. 이 안에 운송용 로봇은 차고 넘치니까.","JPN":"心配しないで。輸送用のロボットはこの中にごまんとあるわ。","ENG":"Relax. There are plenty of transport robots in here.","TWN":"別擔心，這裡面多的是運送用的機器人。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"우선 이터니움은 한곳에 모아놓고, 청동코어가 있는 방으로 가자.","JPN":"まずエタニウムを1か所に集めて、青銅コアのある部屋に行きましょう。","ENG":"Let's stockpile the Eternium in one place first, then head to the room with the Bronze Core.","TWN":"我們先把永恆之金聚集在一個地方，然後去青銅核心所在的房間吧。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"좋아. 이쪽으로 가면 아무 일도 없을 거야.","JPN":"よし。こっちに行けば何もないはずよ。","ENG":"Okay. If we go this way, nothing will happen.","TWN":"好，往這邊走應該不會發生任何事。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L8_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"나탈리아, 네 쪽은 어때?","JPN":"ナタリア、そっちはどう？","ENG":"Natalia, what about your side?","TWN":"那塔利亞，妳那邊怎麼樣？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"LAUGH2"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"포, 폭실이도 이쪽이 맞는 것 같대요.","JPN":"モ、モコもこっちが合ってるみたいって。","ENG":"Fluffox says this way is right too.","TWN":"福、福實也說應該是這邊沒錯。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"FOXIL_UNION_NULL_NULL","text":{"KOREA":"컹.","JPN":"コン。","ENG":"Arf.","TWN":"汪。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_DOG_VOICE_03"},{"id":"L14_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"뭔가 어설프다? 이쯤 되면, 너. 필요 없지 않아?","JPN":"なんか頼りないね。これじゃ、あなたは要らないんじゃない？","ENG":"This feels sloppy. At this point, do we even need you?","TWN":"感覺有點生疏？這種程度，不需要妳了吧？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"느, 능력이 불완전해서 어쩔 수 없잖아. 혼자보다 교차 검증하는 편이 안전하다고.","JPN":"の、能力が不完全だから仕方ないでしょ。クロスチェックしたほうが安全なのよ。","ENG":"M-my foresight is unstable, I can't help that. Plus, cross-checking is safer than going solo.","TWN":"因、因為能力不完善，這也沒辦法，比起一個人，交叉驗證比較安全。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"SURPRISE2"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"그리고 길만 찾는 게 능사는 아니야.","JPN":"それに、道を探せればそれでいいってわけじゃない。","ENG":"And finding the route is not the only job.","TWN":"而且光是找路並不是種本事。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"HATE2"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"청동 메모리코어라는 건, 네가 생각하는 것보다 훨씬 위험한 물건이거든.","JPN":"青銅メモリーコアっていうのは、お前が考えている以上に危険なものなのよ。","ENG":"The Bronze Memory Core is a lot more dangerous than you think.","TWN":"青銅記憶核心是個比妳想像中還要危險許多的物品。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"왜? 셰퍼드의 심장이랑은 다른 거야?","JPN":"なんで？　シェパードの心臓とは違うの？","ENG":"Why? Is it different from a Shepherd's Heart?","TWN":"為什麼？跟牧羊犬之心不一樣嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"비, 비슷하지만 달라요. 셰퍼드의 심장은 나무의 중추기관으로 만들어졌다면.","JPN":"に、似てるけど違います。シェパードの心臓は木の中枢機関でできているけど……","ENG":"S-similar but different. If the Shepherd's Heart is made from the tree's central organ...","TWN":"雖、雖然相似但不一樣，如果說牧羊犬之心是用樹木的中樞部位製成，"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"청동 메모리코어는… 뿌, 뿌리의 일부로 만들어졌어요.","JPN":"青銅メモリーコアは……ね、根の一部でできているんです。","ENG":"The Bronze Memory Core is... m-made from a piece of its root.","TWN":"那青銅記憶核心…則、則是用根部的一部分製作而成。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"부, 북방합의체의 프로젝트는 특정 인자에 높은 동조율을 보이는 적성 개체가 핵심.","JPN":"ほ、北方合意体のプロジェクトでは、特定の因子に高い同調率を見せる適性個体が要です。","ENG":"The Northern Union's projects hinge on compatible subjects who show high resonance with certain factors.","TWN":"北、北方和議會計畫的核心是對特定因子表現出較高同步率的適性個體。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_SERIOUS2"},"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"마트료시카의 경우, 청동코어를 이식할 전투형 마트료시카를 만드는 게 목적이에요.","JPN":"例えばマトリョシカの場合、青銅コアを移植した、戦闘型マトリョシカを作ることを目的としています。","ENG":"For Matryoshka, the goal is to build a combat-type Matryoshkas to implant the Bronze Core into.","TWN":"像俄羅斯娃娃的話，目的是製作能移植青銅核心的戰鬥型俄羅斯娃娃。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_SERIOUS2"},"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"왜 굳이 마트료시카를 선별해요? 메모리코어라는 거, 인형에게는 전부 달려있지 않나?","JPN":"どうしてわざわざマトリョシカを選別するんですか？　メモリーコアっていうのは、人形ならみんな持ってるんでしょう？","ENG":"Why narrow it to Matryoshkas? Don't all the dolls already have a memory core?","TWN":"為什麼非得要挑俄羅斯娃娃？玩偶不是都有記憶核心嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"메모리코어가 사람의 기억을 담는다면, 처, 청동코어는 기억을 불러일으키는 장치예요.","JPN":"メモリーコアが人の記憶を詰めるためのものなら、せ、青銅コアは記憶を呼び起こす装置にあたります。","ENG":"If a memory core stores a person's memories, th-the Bronze Core is a device that evokes those memories.","TWN":"如果說記憶核心是存有人類的記憶，那、那青銅核心就是喚起記憶的裝置。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"스프리건 인자는 감정에 직접적인 영향을 미치니… 평범한 사람이라면 덧씌워진 기억에 집어삼켜질 수도 있죠.","JPN":"スプリガン因子は感情に直接影響を及ぼすから……普通の人は、上書きされた記憶に飲み込まれるかもしれません。","ENG":"The Spriggan Factor directly affects emotions... so an ordinary person could get swallowed by overlaid memories.","TWN":"斯普利根因子會對情感造成直接影響…普通人可能會被籠罩的記憶吞噬。"},"stage":{"bg":"MAVKA_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"이, 인형들의 소체에 복수의 기억을 담는 것도 이걸 대비하기 위해서예요.","JPN":"に、人形の素体に複数の記憶を詰めるのも、それに備えるためです。","ENG":"Putting multiple memories into a doll's vessel is to hedge against that.","TWN":"將復仇的記憶放進玩偶的軀體裡，也是為了防範這一點。"},"stage":{"bg":"MAVKA_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"메모리코어라는 열화판으로 청동코어를 받아들일 수 있는 후보군을 선별한 뒤…….","JPN":"メモリーコアという劣化版で、青銅コアを受け入れる可能性がある候補を選別して……","ENG":"After using the inferior memory cores to screen for candidates who can accept a Bronze Core...","TWN":"用叫做記憶核心的熱化板選出能接受青銅核心的候選名單後……"},"stage":{"bg":"MAVKA_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"저, 적성 개체에게 청동코어를 넘기는 거죠.","JPN":"て、適性個体が見つかったら青銅コアを渡すんです。","ENG":"...Th-they hand the Bronze Core to the compatible subject.","TWN":"再、再將青銅核心轉移到適性個體。"},"stage":{"bg":"MAVKA_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"음… 설명을 들으니까 얼추 이해는 되는데.","JPN":"うん……説明を聞いたらちょっと理解できたけど。","ENG":"Hmm. I kind of get it now that you explained it.","TWN":"嗯…聽完說明之後大概能理解。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"당신, 생각보다 합의체 쪽 사정에 훤하네요?","JPN":"あなた、思ったより合意体の事情に詳しいんですね。","ENG":"You know your way around the Northern Union's business better than I expected.","TWN":"妳比我想像中更清楚和議會那邊的事耶？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"제가 알기로 그 프로젝트들은-.","JPN":"私が知る限りでは、それらのプロジェクトは……","ENG":"As far as I know, those projects–","TWN":"據我所知，那些計畫–"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"…야, 잠깐.","JPN":"……待って。","ENG":"...Hey, stop.","TWN":"…喂，等等。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"SERIOUS3"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_03"},{"id":"L3_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"경고하는데, 나탈리아에게 북방합의체가 어떤 집단인지 밝힐 생각 마.","JPN":"警告しとくけど、ナタリアに北方合意体がどんな集団なのかは明かさない方が身のためよ。","ENG":"I'm warning you, don't spell out what the Northern Union really is to Natalia.","TWN":"我警告妳，別想向那塔利亞表明北方和議會是什麼團體。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"SERIOUS3"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L4_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"뭐야. 꼴에 애는 건들지 말라는 거?","JPN":"何？　子どもは守りたいとか？　らしくないね。","ENG":"Huh? Drawing a line that the kid is off-limits?","TWN":"搞什麼？是要我別動她？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"SERIOUS3"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L5_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"널 위해서 하는 소리야.","JPN":"お前のために言ってるの。","ENG":"I'm saying it for your sake.","TWN":"我這樣說是為了妳好。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L6_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"펠릭스가 아끼는 아이에게 안 좋은 영향이라도 끼쳤다간, 흡혈귀라도 제명에 못 죽을 걸?","JPN":"フェリックスが大事にしてる子に悪い影響を及ぼしたら、いくら吸血鬼でも早死にするわよ。","ENG":"If you sour Felix by messing with a kid she values, even a vampire won't live out her years.","TWN":"要是對緋莉克絲疼惜的孩子造成不好的影響，就連吸血鬼也會死於非命。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L7_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"아껴? 천하의 붉은 마녀가 저 꼬맹이를?","JPN":"大事にする？　天下の赤の魔女が、あの子を？","ENG":"Values? The infamous Red Witch values that pipsqueak?","TWN":"疼惜？天下無敵的紅魔女對那個小毛頭？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"정확하게는 저 아이의 능력을 높이 사는 거야.","JPN":"正確には、あの子の能力を高く評価してるの。","ENG":"To be precise, she values the girl's ability.","TWN":"準確來說是看重那個孩子的能力。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"나탈리아는 이론적인 지식이라면 합의체 연구원들과 어깨를 나란히 할 만큼의 천재거든.","JPN":"ナタリアは理論的な知識だけなら、合意体の研究員と肩を並べるほどの天才よ。","ENG":"Natalia is a prodigy whose theory work stands shoulder to shoulder with Northern Union researchers.","TWN":"論理論上的知識，那塔利亞可是能跟和議會研究員並駕齊驅的天才。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"만약 나탈리아가 진실을 깨닫고 합의체를 등지게 된다면……","JPN":"もしナタリアが真実を知って、合意体に背を向けることになったら……","ENG":"If she ever learns the truth and turns her back on the Northern Union...","TWN":"要是那塔利亞明白真相後背棄和議會的話……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"SERIOUS3"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"그 여자가 널 어떻게 할 것 같아?","JPN":"あの女はお前をどうするかしら？","ENG":"What do you think that woman will do to you?","TWN":"妳覺得那個女人會怎麼處置妳？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"축하해. 내가 너희를 싫어할 이유가 하나 늘었네.","JPN":"おめでとう。私があなたたちを嫌う理由がもう1つ増えたね。","ENG":"Congrats. You just gave me one more reason to hate you people.","TWN":"恭喜，我又多了一個討厭妳們的理由。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"SERIOUS3"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"개죽음 당할 걸 살려줬는데, 난 빼지?","JPN":"犬死にするところを助けてやったんだから、私は外しなさい。","ENG":"I save you from a pathetic death and I don't even get a pass?","TWN":"我救了妳，沒讓妳白白送死，別把我算在內吧？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"포, 폭실아. 둘이 나만 빼고 속닥속닥해.","JPN":"モ、モコ。2人だけでこそこそ話してるよ。","ENG":"Fluffox, they're whispering without me.","TWN":"福、福實，她們兩個拋下我自己竊竊私語。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"혹시 내가 싫은 걸까?","JPN":"私のこと嫌いなのかな？","ENG":"Do they not like me?","TWN":"難道是討厭我嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"FOXIL_UNION_NULL_NULL","text":{"KOREA":"컹.","JPN":"コン。","ENG":"Arf.","TWN":"汪。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_DOG_VOICE_04"},{"id":"L26_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"응…?","JPN":"うん……？","ENG":"Hmm...?","TWN":"嗯…？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L27_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"포, 폭실아. 어디 가?","JPN":"モ、モコ。どこ行くの？","ENG":"Fluffox, where are you going?","TWN":"福、福實，你要去哪？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"우왓. 너랑 얘기하는 사이에 꼬맹이가 달아났잖아.","JPN":"うわっ。あなたと話してる間にあの子が逃げちゃったじゃない。","ENG":"Whoa. While I was talking to you, the kid bolted.","TWN":"哇，和妳說話的時候，小毛頭跑掉了。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"SERIOUS3"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L32_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"안 쫓아가고 뭐해?","JPN":"早く追いかけて！","ENG":"Why aren't you chasing her?","TWN":"還不追上去在幹嘛？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"SERIOUS3"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"3초 뒤, 7시 방향.","JPN":"3秒後、7時方向。","ENG":"In three seconds, on your seven.","TWN":"3秒後，7點鐘方向。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"SERIOUS3"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"온다.","JPN":"来るわ。","ENG":"Incoming.","TWN":"來了。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"SURPRISE2"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"…!!","JPN":"……！！","ENG":"...!!","TWN":"…！！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"사각지대에서 쏜 건데… 전부 막았어?","JPN":"死角から撃ったのに……全部防いだ？","ENG":"I fired from a blind spot... and she blocked all of it?","TWN":"是從死角地帶射的…全部擋下來了嗎？"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_GATLING_START"},{"id":"L42_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"에퉤퉤. 모처럼 마음에 든 향수가 탄약 냄새랑 뒤섞였잖아.","JPN":"ぺっぺっ、せっかくお気に入りの香水をつけたのに、弾薬の匂いと混ざっちゃったよ。","ENG":"Pft pft. The perfume I actually liked is now mixed with gunpowder stink.","TWN":"呸呸呸，難得有喜歡的香水，都跟彈藥的味道混在一起了。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"뭐, 입에서 생강 냄새 나는 시점에서 상관없으려나?","JPN":"まあ、口から生姜の匂いがする時点で別にどうでもいいか。","ENG":"Well, given my breath still smells like ginger, maybe it doesn't matter.","TWN":"反正在這個嘴裡有生薑味的時候，沒關係嗎？"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"와, 너 되게 빠르다.","JPN":"わあ、あなたすごく速いんだね。","ENG":"Wow, you're fast.","TWN":"哇，妳速度真快。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L49_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"몸집은 작은데 파괴력도 상당하네? 혹시 어디 깡패 출신이니?","JPN":"小柄なのにかなりの破壊力じゃん。どこかのごろつき出身？","ENG":"Small frame, but that punch hits hard. Were you some kind of gangster?","TWN":"身體小但破壞力很驚人耶？妳是哪裡的流氓出身嗎？"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L50_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"특수무장 변환. 카쉬탄 일발장전.","JPN":"特殊武装変換。カシュタン一発装填。","ENG":"Special Armament shift. Reloading Kashtan.","TWN":"變換特殊武裝，裝填一發卡什坦。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L1_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"타겟 온…!","JPN":"ターゲットオン……！","ENG":"Target on...!","TWN":"目標來…！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L4_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"무식하게 얼굴 마주치자마자 치고 받긴. 북방합의체 실험체들은 뇌가 근육인가?","JPN":"顔合わせた途端に喧嘩だなんて、北方合意体の実験体はみんな脳筋なの？","ENG":"Brawling the instant you lock eyes. Are Northern Union test subjects just muscle for brains?","TWN":"不要一遇見就魯莽地打起來，北方和議會實驗體的腦袋是肌肉嗎？"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"SERIOUS3"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L5_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"한 녀석은 흡혈귀 녀석이 맡아줄 테니, 다른 한 쪽은…….","JPN":"片方は吸血鬼が相手するから、もう片方は……","ENG":"One will take on the vampire. As for the other one...","TWN":"一個傢伙吸血鬼會負責，另一個……"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"HATE2"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"크윽!?","JPN":"くっ！？","ENG":"Kgh?!","TWN":"咳呃！？"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"DESPAIR2"}}},"sfx":"FX_COMBAT_ALL_HIT_METAL_06"},{"id":"L9_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"매정한 녀석 같으니. 오랜만에 만났는데 환영인사도 안 받아주는 거냐?","JPN":"この薄情者。久々に会ったというのに歓迎の挨拶もなしか？","ENG":"How heartless. After so long, you're not even going to say hello?","TWN":"真是個無情的傢伙，這麼久沒見了，居然不接受我的歡迎問候？"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L10_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"너… 방금 머리를 부술 생각으로 휘두른 거야?","JPN":"お前……頭潰す気で振り回したわね？","ENG":"You... you just swung to crush my head!","TWN":"妳…剛才是想砸碎我的頭嗎？"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"SURPRISE2"}}}},{"id":"L11_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"그런 거에 맞았다간 죽는다고!","JPN":"そんなものに当たったら死んじゃうじゃない！","ENG":"A hit like that would kill me!","TWN":"要是被那種東西砸中會沒命的！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"DESPAIR2"}}}},{"id":"L12_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"어차피 피할 거면서 엄살은.","JPN":"どうせ避けるくせに、大袈裟じゃのう。","ENG":"You were going to dodge anyway. Quit whining.","TWN":"反正妳都會躲開，在無病呻吟什麼？"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"DESPAIR2"}}}},{"id":"L13_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"그리고 넌 맞아도 싸.","JPN":"それに、お主は痛い目にあって当然じゃ。","ENG":"Besides, you have it coming.","TWN":"而且妳被砸中也是活該。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"DESPAIR2"}}}},{"id":"L14_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"이게…!!","JPN":"この……！！","ENG":"Why you...!!","TWN":"這…！！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_04"},{"id":"L20_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"기억에 있다. 저 녀석, 싸워본 상대야.","JPN":"記憶にある。あいつ、戦ったことがある相手ね。","ENG":"I remember. I've fought her before.","TWN":"我記得，那個傢伙是打鬥過的對手。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"예지능력은 불안정하지만 코앞의 수를 내다보는 것 정도는 가능하니, 이길 수 있…….","JPN":"予知能力は不安定だけど、近い未来を覗くぐらいはできるし、勝てる……","ENG":"My foresight is shaky, but seeing a move or two ahead should be enough to win...","TWN":"雖然預知能力不穩定，但至少能看清眼前的數字，所以應該能贏……"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"어라?","JPN":"あれ？","ENG":"Huh?","TWN":"咦？"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"SURPRISE2"}}}},{"id":"L30_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"자, 잠깐만! 뭐 이렇게 빨라?","JPN":"ま、待って！　なんて速さなの？","ENG":"Hold on. How are you this fast?","TWN":"等、等一下！怎麼這麼快？"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_EARTHQUAKE_02"},{"id":"L31_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"그럼, 동결이 해제된 뒤 얼마 되지도 않은 몸상태가 최선이겠냐?","JPN":"凍結から目覚めてまだ日が浅いのじゃ。本調子なわけがなかろう。","ENG":"Do you really think this is my best right after thawing out?","TWN":"當然，解除凍結才沒過多久，難不成身體會是最佳狀態嗎？"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"반쪽 짜리라고는 해도 환상종인 몸이다. 어린 것한테 맞고만 살면 폼이 안 살지.","JPN":"半分とはいえ幻想種じゃ。若者にやられてばかりというのも格好がつかん。","ENG":"Even a half-blood Bygone is still a Bygone. Getting beat up by a kid would look bad.","TWN":"雖然說是半調子，卻是夢幻品種，如果只是被小毛頭打就毫無架勢了。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"…흥. 확실히 놀랐지만 금지구역의 설비를 재가동시켜 너희가 오게 된 건 의도대로야.","JPN":"……ふん。確かに驚きはしたけど、禁止区域の設備を再稼働させてお前たちを誘き寄せたのは、私の狙いどおりよ。","ENG":"...Hmph. I'm impressed, but rebooting the off-limits zone's systems to draw you here went exactly as planned.","TWN":"…嗯，雖然的確嚇了一跳，但重新啟動禁區設備，讓妳們來到這裡正合我意。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"SERIOUS3"}}}},{"id":"L34_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"어떤 방식이든 민병단과는 마찰을 빚게 되니, 발 빠른 주요 전력만 오도록 유도했지.","JPN":"どんな形であれ民兵団とはぶつかることになるから、主要戦力だけ先に来るように誘導したの。","ENG":"One way or another you would clash with the militia, so I steered it so only the quick strike force would show up.","TWN":"無論用什麼方式都會和民兵團產生摩擦，所以就只引誘了速度較快的主要戰力前來。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_HATE"}}}},{"id":"L35_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"호오~. 각개격파를 하시겠다?","JPN":"ほお、1人ずつ倒すつもりか。","ENG":"Oh? Planning to pick us off in detail, are we?","TWN":"吼喔～是要各個擊破嗎？"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_HATE"}}}},{"id":"L36_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"제법 머리를 썼다만, 기계팔도 없이 나랑 싸울 수 있겠냐?","JPN":"随分頭を使ったようじゃが、機械の腕もなくわしと戦えると思っておるのか？","ENG":"Nice strategy, but do you think you can fight me without your machine claws?","TWN":"雖然妳很會動頭腦，但沒有機械手臂能和我戰鬥嗎？"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_HATE"}}}},{"id":"L40_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"알아. 맨손으로 너 같은 짐승이랑 싸우는 건 미친 짓이지.","JPN":"思ってないわ。素手でお前みたいな獣と戦うなんてあり得ないもの。","ENG":"I know. Trading blows bare-handed with a beast like you would be insane.","TWN":"我知道，赤手空拳和妳這種禽獸戰鬥是瘋狂之舉。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"그래서 설비를 재가동시켰다고 말했잖아?","JPN":"だから設備を再稼働させたって言ったでしょ？","ENG":"Which is why I said I reactivated the systems.","TWN":"所以我不是說過重新啟動設備了嗎？"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":null,"text":{"KOREA":"대화력전 사격 통제 모듈–– ZEMINIA.","JPN":"対火力戦射撃制御モジュール──ZEMINIA。","ENG":"Counterfire warfare shooting control module–– ZEMINIA.","TWN":"反火力作戰射擊控制模組–– ZEMINIA。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"SERIOUS3"},"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L45_1","type":"dialog","speaker":null,"text":{"KOREA":"섬멸 프로그램 가동. 우선 타겟 선출–––––.","JPN":"殲滅プログラム稼働。優先ターゲットを選出────。","ENG":"Annihilation Program online. Prioritizing targets–––––.","TWN":"啟動殲滅程式，先選出目標–––––"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"SERIOUS3"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"섬멸프로그램? 이건 또 무슨 신박한 자살 방법이냐?","JPN":"殲滅プログラム？　新種の自殺方法か？","ENG":"Annihilation Program? Is that a fancy way to say you are going to kill yourself?","TWN":"殲滅程式？這又是什麼新穎的自殺方法？"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"SERIOUS3"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L49_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"대부분의 병기는 적을 우선 타격하도록 프로그래밍 되어 있어.","JPN":"ほとんどの兵器は、敵を優先的に攻撃するようにプログラムされているわ。","ENG":"Most of these weapons are set to prioritize enemies.","TWN":"大部分的兵器都被編制成優先打擊敵人。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_SERIOUS"}}}},{"id":"L50_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"구식이지만, 정보 갱신이 안된 덕에 합의체 소속으로 인식되는 나.","JPN":"旧式だけど、情報が更新されていないおかげで合意体所属として認識される私。","ENG":"They're old, but because the databases were never updated I still read as part of the Northern Union.","TWN":"雖然有些老套，但由於資訊沒更新，所以被辨識為隸屬和議會的我。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"그리고 북방합의체의 실험으로 탄생한 흡혈귀와 마트료시카 인형.","JPN":"そして、北方合意体の実験で生まれた吸血鬼とマトリョシカ人形。","ENG":"While these two are a vampire from the Northern Union's experiments and a Matryoshka doll.","TWN":"還有因為北方和議會的實驗誕生的吸血鬼和俄羅斯娃娃。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"LENORE_UNION_NULL_ORIGIN","text":{"KOREA":"반면, 넌 어떻지?","JPN":"でも、お前は違うわよね？","ENG":"But what about you?","TWN":"反之，妳怎麼樣？"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"에잉. 하여튼 요즘 것들은 뭐만 하면 기계 힘으로 해결하려 들지.","JPN":"ったく、最近の若者はなんでも機械の力を借りようとする。","ENG":"Ugh. Kids these days try to solve everything with machines.","TWN":"唉唷，總之最近的人動不動就想藉助機械力量來解決。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LENORE_UNION_NULL_ORIGIN","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"음…….","JPN":"うーん……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"뭐, 좋다.","JPN":"まあ、よい。","ENG":"Fine.","TWN":"嗯，好。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L8_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"이 참에 연장자로서 그 버르장머리를 고쳐주지.","JPN":"年長者として、この機会にしっかりと礼儀を叩き込んでやろう。","ENG":"As your elder, I will knock some manners into you.","TWN":"我身為長輩，就趁這機會改掉你們的毛病。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};